import { Link } from 'react-router-dom';
import 'components/services/ServiceCard.css'

const ServiceCard = ({ icon: Icon, price, priceLabel, pricePrefix, title, description }) => {
  return (
    <div className="service-card">
      <div className="card-header">
        <div className="card-icon-wrapper">
          <Icon className="card-icon icon-neon" />
        </div>
        
        <div className="card-price-info">
          {priceLabel && <span className="card-price-label">{priceLabel}</span>}
          <span className="card-price">
            {pricePrefix && `${pricePrefix} `} 
            {price}
          </span>
        </div>
      </div>
      
      <h3 className="card-title">{title}</h3>
      <p className="card-description">{description}</p>
      
      <div className="card-footer">
        <a href='htpps://wa.me/18998089932?text=Olá, Gostaria de agendar um serviço com o Cortex Studio!'
        className="btn btn-secondary"
        target='_blanck'
        rel=''
        >Agendar</a>
        {/* <Link to="#" className="btn btn-primary">Saiba mais</Link> */} 
      </div>
    </div>
  );
};

export default ServiceCard;
